  8→import SwiftUI
  9→import Swinject
 10→
 11→// MARK: - Social Feed View
 12→
 13→struct SocialFeedView: View {
 14→    @State private var viewModel: SocialFeedViewModel
 15→    @State private var showComments: FeedPost?
 16→    @Environment(\.dependencyResolver) private var resolver
 17→
 18→    init(viewModel: SocialFeedViewModel) {
 19→        _viewModel = State(initialValue: viewModel)
 20→    }
 21→
 22→    var body: some View {
 23→        ScrollView {
 24→            LazyVStack(spacing: FitTodaySpacing.md) {
 25→                ForEach(viewModel.posts) { post in
 26→                    FeedPostCardView(
 27→                        post: post,
 28→                        isLiked: viewModel.isPostLiked(post),
 29→                        isOwnPost: viewModel.isCurrentUser(post.authorId),
 30→                        onLike: {
 31→                            Task { await viewModel.toggleLike(postId: post.id) }
 32→                        },
 33→                        onComment: {
 34→                            showComments = post
 35→                        },
 36→                        onDelete: {
 37→                            Task { await viewModel.deletePost(post.id) }
 38→                        }
 39→                    )
 40→                }
 41→
 42→                if viewModel.posts.isEmpty && !viewModel.isLoading {
 43→                    emptyFeedView
 44→                }
 45→
 46→                if viewModel.isLoading {
 47→                    ProgressView()
 48→                        .padding(.vertical, FitTodaySpacing.xl)
 49→                }
 50→            }
 51→            .padding()
 52→        }
 53→        .refreshable {
 54→            await viewModel.loadFeed()
 55→        }
 56→        .task {
 57→            viewModel.startObserving()
 58→        }
 59→        .onDisappear {
 60→            viewModel.stopObserving()
 61→        }
 62→        .navigationTitle("Feed")
 63→        .sheet(item: $showComments) { post in
 64→            if let feedRepo = resolver.resolve(FeedRepository.self),
 65→               let authRepo = resolver.resolve(AuthenticationRepository.self) {
 66→                FeedCommentsView(
 67→                    viewModel: FeedCommentsViewModel(
 68→                        feedRepository: feedRepo,
 69→                        authRepository: authRepo,
 70→                        postId: post.id
 71→                    )
 72→                )
 73→                .presentationDetents([.medium, .large])
 74→            }
 75→        }
 76→        .alert("Erro", isPresented: Binding(
 77→            get: { viewModel.errorMessage != nil },
 78→            set: { _ in viewModel.errorMessage = nil }
 79→        )) {
 80→            Button("Ok", role: .cancel) {}
 81→        } message: {
 82→            Text(viewModel.errorMessage ?? "")
 83→        }
 84→    }
 85→
 86→    private var emptyFeedView: some View {
 87→        VStack(spacing: FitTodaySpacing.md) {
 88→            Image(systemName: "person.3.fill")
 89→                .font(.system(size: 48))
 90→                .foregroundStyle(FitTodayColor.textSecondary)
 91→
 92→            Text("Nenhum post ainda")
 93→                .font(.headline)
 94→
 95→            Text("Complete um treino e compartilhe com seu grupo!")
 96→                .font(.subheadline)
 97→                .foregroundStyle(FitTodayColor.textSecondary)
 98→                .multilineTextAlignment(.center)
 99→        }
100→        .padding(.vertical, 60)
101→    }
102→}
