  2→//  FirebaseFeedRepository.swift
  3→//  FitToday
  4→//
  5→//  Created by Claude on 12/03/26.
  6→//
  7→
  8→import Foundation
  9→
 10→// MARK: - Firebase Feed Repository
 11→
 12→final class FirebaseFeedRepository: FeedRepository, @unchecked Sendable {
 13→    private let feedService: FirebaseFeedService
 14→    private let storageService: StorageServicing
 15→
 16→    init(feedService: FirebaseFeedService, storageService: StorageServicing) {
 17→        self.feedService = feedService
 18→        self.storageService = storageService
 19→    }
 20→
 21→    func createPost(_ post: FeedPost, mediaData: Data?) async throws -> FeedPost {
 22→        var updatedPost = post
 23→
 24→        // Upload media if present
 25→        if let mediaData {
 26→            let ext = post.mediaType == .video ? "mp4" : "jpg"
 27→            let path = "feed/\(post.authorId)/\(post.id).\(ext)"
 28→            let url = try await storageService.uploadImage(data: mediaData, path: path)
 29→            updatedPost = FeedPost(
 30→                id: post.id,
 31→                authorId: post.authorId,
 32→                authorName: post.authorName,
 33→                authorPhotoURL: post.authorPhotoURL,
 34→                mediaURL: url,
 35→                mediaType: post.mediaType,
 36→                caption: post.caption,
 37→                workoutTitle: post.workoutTitle,
 38→                workoutDurationMinutes: post.workoutDurationMinutes,
 39→                exerciseCount: post.exerciseCount,
 40→                totalVolume: post.totalVolume,
 41→                groupId: post.groupId,
 42→                createdAt: post.createdAt
 43→            )
 44→        }
 45→
 46→        let fbPost = FBFeedPost(from: updatedPost)
 47→        let created = try await feedService.createPost(fbPost)
 48→        guard let domain = created.toDomain() else {
 49→            throw FeedError.postNotFound
 50→        }
 51→        return domain
 52→    }
 53→
 54→    func deletePost(_ postId: String, authorId: String) async throws {
 55→        // Delete media from storage (best effort)
 56→        let jpgPath = "feed/\(authorId)/\(postId).jpg"
 57→        let mp4Path = "feed/\(authorId)/\(postId).mp4"
 58→        try? await storageService.deleteImage(path: jpgPath)
 59→        try? await storageService.deleteImage(path: mp4Path)
 60→
 61→        try await feedService.deletePost(postId)
 62→    }
 63→
 64→    func getPosts(groupId: String, limit: Int, after: Date?) async throws -> [FeedPost] {
 65→        let fbPosts = try await feedService.getPosts(groupId: groupId, limit: limit, after: after)
 66→        return fbPosts.compactMap { $0.toDomain() }
 67→    }
 68→
 69→    func observePosts(groupId: String) -> AsyncStream<[FeedPost]> {
 70→        AsyncStream { continuation in
 71→            let task = Task {
 72→                for await fbPosts in await feedService.observePosts(groupId: groupId) {
 73→                    let posts = fbPosts.compactMap { $0.toDomain() }
 74→                    continuation.yield(posts)
 75→                }
 76→                continuation.finish()
 77→            }
 78→
 79→            continuation.onTermination = { _ in
 80→                task.cancel()
 81→            }
 82→        }
 83→    }
 84→
 85→    func toggleLike(postId: String, userId: String) async throws -> Bool {
 86→        try await feedService.toggleLike(postId: postId, userId: userId)
 87→    }
 88→
 89→    func addComment(_ comment: FeedComment) async throws {
 90→        let fbComment = FBFeedComment(from: comment)
 91→        try await feedService.addComment(fbComment)
 92→    }
 93→
 94→    func getComments(postId: String, limit: Int) async throws -> [FeedComment] {
 95→        let fbComments = try await feedService.getComments(postId: postId, limit: limit)
 96→        return fbComments.compactMap { $0.toDomain() }
 97→    }
 98→
 99→    func observeComments(postId: String) -> AsyncStream<[FeedComment]> {
100→        AsyncStream { continuation in
101→            let task = Task {
102→                for await fbComments in await feedService.observeComments(postId: postId) {
103→                    let comments = fbComments.compactMap { $0.toDomain() }
104→                    continuation.yield(comments)
105→                }
106→                continuation.finish()
107→            }
108→
109→            continuation.onTermination = { _ in
110→                task.cancel()
111→            }
112→        }
113→    }
114→}
