246→// MARK: - Month Calendar View
247→
248→struct MonthCalendarView: View {
249→    @Binding var selectedDate: Date
250→    let highlightedDays: Set<DateComponents>
251→
252→    // BUG 7 FIX: use Monday-first week to match startOfWeek used by weekly stats.
253→    private let calendar: Calendar = {
254→        var cal = Calendar.current
255→        cal.firstWeekday = 2 // Monday = 2
256→        return cal
257→    }()
258→    // Mon, Tue, Wed, Thu, Fri, Sat, Sun
259→    private let daysOfWeek = ["S", "T", "Q", "Q", "S", "S", "D"]
260→
261→    private var monthDays: [Date?] {
262→        let interval = calendar.dateInterval(of: .month, for: selectedDate)!
263→        let firstDay = interval.start
264→        // weekday in Calendar.current is 1=Sun … 7=Sat.
265→        // Convert to Monday-first column index: Mon=0 … Sun=6.
266→        let firstWeekday = Calendar.current.component(.weekday, from: firstDay)
267→        let mondayFirstOffset = (firstWeekday - 2 + 7) % 7
268→        let daysInMonth = calendar.range(of: .day, in: .month, for: selectedDate)!.count
269→
270→        var days: [Date?] = Array(repeating: nil, count: mondayFirstOffset)
271→
272→        for day in 1...daysInMonth {
273→            if let date = calendar.date(byAdding: .day, value: day - 1, to: firstDay) {
274→                days.append(date)
275→            }
276→        }
277→
278→        // Pad to complete last week
279→        while days.count % 7 != 0 {
280→            days.append(nil)
281→        }
282→
283→        return days
284→    }
285→
286→    var body: some View {
287→        VStack(spacing: FitTodaySpacing.sm) {
288→            // Month navigation
289→            HStack {
290→                Button {
291→                    withAnimation {
292→                        selectedDate = calendar.date(byAdding: .month, value: -1, to: selectedDate)!
293→                    }
294→                } label: {
295→                    Image(systemName: "chevron.left")
296→                        .foregroundStyle(FitTodayColor.textSecondary)
297→                }
298→
299→                Spacer()
300→
301→                Text(selectedDate, format: .dateTime.month(.wide).year())
302→                    .font(FitTodayFont.ui(size: 16, weight: .semiBold))
303→                    .foregroundStyle(FitTodayColor.textPrimary)
304→
305→                Spacer()
306→
307→                Button {
308→                    withAnimation {
309→                        selectedDate = calendar.date(byAdding: .month, value: 1, to: selectedDate)!
310→                    }
311→                } label: {
312→                    Image(systemName: "chevron.right")
313→                        .foregroundStyle(FitTodayColor.textSecondary)
314→                }
315→            }
316→            .padding(.horizontal, FitTodaySpacing.sm)
317→
318→            // Days of week header
319→            HStack(spacing: 0) {
320→                ForEach(daysOfWeek, id: \.self) { day in
321→                    Text(day)
322→                        .font(FitTodayFont.ui(size: 12, weight: .medium))
323→                        .foregroundStyle(FitTodayColor.textTertiary)
324→                        .frame(maxWidth: .infinity)
325→                }
326→            }
327→
328→            // Calendar grid
329→            LazyVGrid(columns: Array(repeating: GridItem(.flexible()), count: 7), spacing: FitTodaySpacing.xs) {
330→                ForEach(Array(monthDays.enumerated()), id: \.offset) { _, date in
331→                    if let date {
332→                        DayCell(
333→                            date: date,
334→                            isHighlighted: isHighlighted(date),
335→                            isSelected: calendar.isDate(date, inSameDayAs: selectedDate),
336→                            isToday: calendar.isDateInToday(date)
337→                        ) {
338→                            selectedDate = date
339→                        }
340→                    } else {
341→                        Color.clear
342→                            .frame(width: 36, height: 36)
343→                    }
344→                }
345→            }
346→        }
347→        .padding(FitTodaySpacing.md)
348→        .background(
349→            RoundedRectangle(cornerRadius: FitTodayRadius.md)
350→                .fill(FitTodayColor.surface)
351→        )
352→    }
353→
354→    private func isHighlighted(_ date: Date) -> Bool {
355→        let components = calendar.dateComponents([.year, .month, .day], from: date)
356→        return highlightedDays.contains(components)
357→    }
358→}
