                                .foregroundStyle(FitTodayColor.brandPrimary.gradient)
                                .cornerRadius(4)
                            }
                            .chartYAxis {
                                AxisMarks(values: .automatic(desiredCount: 4)) { value in
                                    AxisGridLine()
                                    AxisValueLabel {
                                        if let intVal = value.as(Int.self) {
                                            Text("\(intVal)")
                                                .font(FitTodayFont.ui(size: 10, weight: .medium))
                                                .foregroundStyle(FitTodayColor.textTertiary)
                                        }
                                    }
                                }
                            }
                            .chartXAxis {
                                AxisMarks { value in
                                    AxisValueLabel {
                                        if let label = value.as(String.self) {
                                            Text(label)
                                                .font(FitTodayFont.ui(size: 10, weight: .medium))
                                                .foregroundStyle(FitTodayColor.textSecondary)
                                        }
                                    }
                                }
                            }
                            .animation(.easeOut(duration: 0.8), value: chartAnimated)
                            .frame(height: 180)
                        }
                    }

                    // Weekly Chart — Minutes per Day
                    if !viewModel.dailyEntries.isEmpty {
                        chartSection(
                            title: "Minutos por Dia",
                            subtitle: "Últimos 7 dias"
                        ) {
                            Chart(viewModel.dailyEntries) { entry in
                                BarMark(
                                    x: .value("Dia", entry.dayLabel),
                                    y: .value("Minutos", chartAnimated ? entry.minutes : 0)
                                )
                                .foregroundStyle(Color.orange.gradient)
                                .cornerRadius(4)
                            }
                            .chartYAxis {
                                AxisMarks(values: .automatic(desiredCount: 4)) { value in
                                    AxisGridLine()
                                    AxisValueLabel {
                                        if let intVal = value.as(Int.self) {
                                            Text("\(intVal)")
                                                .font(FitTodayFont.ui(size: 10, weight: .medium))
                                                .foregroundStyle(FitTodayColor.textTertiary)
                                        }
                                    }
                                }
                            }
                            .chartXAxis {
                                AxisMarks { value in
                                    AxisValueLabel {
                                        if let label = value.as(String.self) {
                                            Text(label)
                                                .font(FitTodayFont.ui(size: 10, weight: .medium))
                                                .foregroundStyle(FitTodayColor.textSecondary)
                                        }
                                    }
                                }
                            }
                            .animation(.easeOut(duration: 0.8).delay(0.15), value: chartAnimated)
                            .frame(height: 180)
                        }
                    }

                    // Monthly Chart — Workouts per Week
                    if !viewModel.weeklyEntries.isEmpty {
                        chartSection(
                            title: "Treinos por Semana",
                            subtitle: "Últimas 4 semanas"
                        ) {
                            Chart(viewModel.weeklyEntries) { entry in
                                BarMark(
                                    x: .value("Semana", entry.weekLabel),
                                    y: .value("Treinos", chartAnimated ? entry.workouts : 0)
                                )
                                .foregroundStyle(Color.green.gradient)
                                .cornerRadius(4)
                            }
                            .chartYAxis {
                                AxisMarks(values: .automatic(desiredCount: 4)) { value in
                                    AxisGridLine()
                                    AxisValueLabel {
                                        if let intVal = value.as(Int.self) {
                                            Text("\(intVal)")
                                                .font(FitTodayFont.ui(size: 10, weight: .medium))
                                                .foregroundStyle(FitTodayColor.textTertiary)
                                        }
                                    }
                                }
                            }
                            .chartXAxis {
                                AxisMarks { value in
                                    AxisValueLabel {
                                        if let label = value.as(String.self) {
                                            Text(label)
                                                .font(FitTodayFont.ui(size: 10, weight: .medium))
                                                .foregroundStyle(FitTodayColor.textSecondary)
                                        }
                                    }
                                }
                            }
                            .animation(.easeOut(duration: 0.8).delay(0.3), value: chartAnimated)
                            .frame(height: 180)
                        }
                    }

                    // PRO-74: Consistency Heatmap (free)
                    ConsistencyHeatmapView(workoutDates: viewModel.heatmapData)

                    // PRO-75: Weekly Volume Chart (Pro+)
                    if viewModel.entitlement.isPro {
                        WeeklyVolumeChartView(
                            entries: viewModel.volumeEntries,
                            animated: chartAnimated
                        )
                    } else {
                        proLockedSection(
                            title: "Volume Semanal",
                            description: "Acompanhe sua evolução de volume de treino"
                        )
                    }

                    // PRO-76: Weight Progress Chart (Pro+)
                    if viewModel.entitlement.isPro {
                        WeightProgressChartView(
                            entries: viewModel.weightEntries,
                            animated: chartAnimated
                        )
                    } else {
                        proLockedSection(
                            title: "Evolução de Peso",
                            description: "Visualize sua progressão de peso com dados do Apple Health"
                        )
                    }
                }
                .padding(FitTodaySpacing.md)
                .onAppear {
                    guard !chartAnimated else { return }
                    if reduceMotion {
                        chartAnimated = true
                    } else {
                        withAnimation(.easeOut(duration: 0.8).delay(0.1)) {
                            chartAnimated = true
                        }
                    }
                }
                } // end else (no error)
            } else {
                VStack(spacing: FitTodaySpacing.md) {
                    HStack(spacing: FitTodaySpacing.md) {
                        ForEach(0..<3, id: \.self) { _ in
                            RoundedRectangle(cornerRadius: FitTodayRadius.md)
                                .fill(FitTodayColor.surface)
                                .frame(height: 80)
                                .shimmer()
                        }
                    }
                    RoundedRectangle(cornerRadius: FitTodayRadius.md)
                        .fill(FitTodayColor.surface)
                        .frame(height: 200)
                        .shimmer()
                    RoundedRectangle(cornerRadius: FitTodayRadius.md)
                        .fill(FitTodayColor.surface)
                        .frame(height: 200)
                        .shimmer()
                }
                .padding(FitTodaySpacing.md)
            }
        }
        .scrollIndicators(.hidden)
        .task {
            if viewModel == nil {
                viewModel = ActivityStatsViewModel(resolver: resolver)
            }
            await viewModel?.loadStats()
        }
        .refreshable {
            await viewModel?.loadStats()
        }
    }

    // MARK: - Summary Section

    private func summarySection(viewModel: ActivityStatsViewModel) -> some View {
        let stats = viewModel.stats ?? .empty

        return VStack(spacing: FitTodaySpacing.md) {
            // Week row
            VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
                Text("Esta Semana")
                    .font(FitTodayFont.ui(size: 17, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                HStack(spacing: FitTodaySpacing.md) {
                    ActivityStatCard(title: "Treinos", value: "\(stats.weekWorkoutsCount)", icon: "dumbbell")
                    ActivityStatCard(title: "Tempo", value: formatMinutes(stats.weekTotalMinutes), icon: "clock")
                    ActivityStatCard(title: "Calorias", value: "\(stats.weekTotalCalories)", icon: "flame")
                }
            }

            // Month row
            VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
                Text("Este Mês")
                    .font(FitTodayFont.ui(size: 17, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                HStack(spacing: FitTodaySpacing.md) {
                    ActivityStatCard(title: "Treinos", value: "\(stats.monthWorkoutsCount)", icon: "dumbbell")
                    ActivityStatCard(title: "stats.streak_days".localized, value: "\(stats.currentStreak)", icon: "flame.fill")
                    ActivityStatCard(title: "Tempo", value: formatMinutes(stats.monthTotalMinutes), icon: "clock")
                }
            }
        }
    }

    // MARK: - Chart Section

    private func chartSection<Content: View>(
        title: String,
        subtitle: String,
        @ViewBuilder chart: () -> Content
    ) -> some View {
        VStack(alignment: .leading, spacing: FitTodaySpacing.sm) {
            VStack(alignment: .leading, spacing: 2) {
                Text(title)
                    .font(FitTodayFont.ui(size: 17, weight: .bold))
                    .foregroundStyle(FitTodayColor.textPrimary)

                Text(subtitle)
                    .font(FitTodayFont.ui(size: 12, weight: .medium))
                    .foregroundStyle(FitTodayColor.textTertiary)
            }

            chart()
                .padding(FitTodaySpacing.md)
                .background(
                    RoundedRectangle(cornerRadius: FitTodayRadius.md)
                        .fill(FitTodayColor.surface)
                )
        }
    }

    // MARK: - Helpers

    private func formatMinutes(_ minutes: Int) -> String {
        if minutes >= 60 {
            let h = minutes / 60
            let m = minutes % 60
            return m > 0 ? "\(h)h \(m)m" : "\(h)h"
        }
        return "\(minutes)m"
    }

    // MARK: - Pro Locked Section

    private func proLockedSection(title: String, description: String) -> some View {
        VStack(spacing: FitTodaySpacing.md) {
